const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();

const codingQuestions = [
  // Lesson 26 - ES6+ Features
  {lessonId:26,difficulty:"Easy",topic:"ES6+ Features",title:"Destructuring Practice",problemStatement:"Use destructuring to extract values from nested objects and arrays. Write functions showing default values, renaming, and rest patterns.",examples:"const {a:renamed=0} = obj. const [first,...rest] = arr.",starterCodeJs:"function destructuringDemo() {\n  const user = {name:'Alice',age:30,address:{city:'NYC',zip:'10001'}};\n  const {name, age=18, address:{city}} = user;\n  const [first, second='default', ...rest] = [1, undefined, 3, 4];\n  // Swap variables without temp\n  let a = 1, b = 2;\n  [a, b] = [b, a];\n  return {name, age, city, first, second, rest, a, b};\n}",hints:"Default values fill in when property is undefined. Rename with colon: {name:alias}. Rest collects remaining elements.",solutionExplanation:"Destructuring reduces repetition. Defaults prevent undefined. Rename to avoid conflicts. Rest captures remaining in a new array."},
  {lessonId:26,difficulty:"Medium",topic:"ES6+ Features",title:"Generator Fibonacci",problemStatement:"Write a generator function that produces Fibonacci numbers indefinitely. Use it with a take() helper to get the first n Fibonacci numbers.",examples:"[...take(fibonacci(), 8)] === [0, 1, 1, 2, 3, 5, 8, 13]",starterCodeJs:"function* fibonacci() {\n  let [a, b] = [0, 1];\n  while (true) { yield a; [a, b] = [b, a + b]; }\n}\nfunction* take(gen, n) {\n  for (const val of gen) { if (n-- <= 0) break; yield val; }\n}\nfunction* range(start, end, step = 1) {\n  for (let i = start; i < end; i += step) yield i;\n}\nconsole.log([...take(fibonacci(), 8)]); // [0,1,1,2,3,5,8,13]",hints:"Generator maintains state between yields. [a,b]=[b,a+b] updates both variables atomically. take() limits an infinite generator.",solutionExplanation:"Generators enable lazy infinite sequences. Data is produced on demand, not all at once."},
  {lessonId:26,difficulty:"Medium",topic:"ES6+ Features",title:"Proxy Validation",problemStatement:"Use Proxy to add validation to an object: age must be 0-120, name must be non-empty string. Throw TypeError on invalid assignment.",examples:"user.age = 150 throws TypeError. user.name = '' throws TypeError.",starterCodeJs:"function createValidatedUser(initial = {}) {\n  const validators = {\n    age: v => (typeof v === 'number' && v >= 0 && v <= 120) || `Age must be 0-120, got ${v}`,\n    name: v => (typeof v === 'string' && v.trim().length > 0) || 'Name must be non-empty string'\n  };\n  return new Proxy({ ...initial }, {\n    set(target, prop, value) {\n      if (validators[prop]) {\n        const result = validators[prop](value);\n        if (result !== true) throw new TypeError(result);\n      }\n      target[prop] = value;\n      return true;\n    }\n  });\n}",hints:"Proxy set trap intercepts assignment. Return true to confirm set succeeded. Throw TypeError for validation failures.",solutionExplanation:"Proxy set trap enables runtime validation without getters/setters on each property. Validators map defines rules per property."},
  {lessonId:26,difficulty:"Hard",topic:"ES6+ Features",title:"WeakMap Private Data",problemStatement:"Use WeakMap to create truly private instance data for a class. No underscore prefix - the data is genuinely inaccessible from outside.",examples:"const user = new User('Alice'); user.name is undefined. user.getName() works.",starterCodeJs:"const _private = new WeakMap();\nclass User {\n  constructor(name, password) {\n    _private.set(this, { name, password, loginCount: 0 });\n  }\n  getName() { return _private.get(this).name; }\n  checkPassword(pw) {\n    const priv = _private.get(this);\n    if (pw === priv.password) { priv.loginCount++; return true; }\n    return false;\n  }\n  getLoginCount() { return _private.get(this).loginCount; }\n}\nconst u = new User('Alice', 'secret');\nconsole.log(u.name); // undefined\nconsole.log(u.getName()); // 'Alice'",hints:"WeakMap keys are the instances. Data is garbage collected when instance is collected. Cannot be accessed without the WeakMap reference.",solutionExplanation:"WeakMap provides true privacy - the data is only accessible within the module scope where _private is defined."},
  {lessonId:26,difficulty:"Easy",topic:"ES6+ Features",title:"Template Literal Tag",problemStatement:"Write a highlight tagged template that wraps interpolated values in <mark> tags for HTML display. Also write a safe tag that escapes HTML in interpolations.",examples:"highlight`Hello ${'World'} and ${42}` -> 'Hello <mark>World</mark> and <mark>42</mark>'",starterCodeJs:"function highlight(strings, ...values) {\n  return strings.reduce((result, str, i) => {\n    const val = values[i - 1];\n    return result + (val !== undefined ? `<mark>${val}</mark>` : '') + str;\n  });\n}\nfunction safe(strings, ...values) {\n  const escape = str => String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;');\n  return strings.reduce((acc, str, i) => acc + escape(values[i-1] ?? '') + str);\n}\nconsole.log(highlight`Hello ${'World'} and ${42}`);",hints:"Tagged template: strings is array of string parts, values is array of interpolated values. Interleave them.",solutionExplanation:"Tagged templates process template literals. strings has one more element than values. Reduce interleaves them with transformations."},
  {lessonId:26,difficulty:"Medium",topic:"ES6+ Features",title:"Map and Set Operations",problemStatement:"Demonstrate Map and Set with practical examples: word frequency counter with Map, unique visitors with Set, and converting between them.",examples:"wordFreq('hello world hello') -> Map{hello:2, world:1}. uniqueVisitors with Set.",starterCodeJs:"function wordFrequency(text) {\n  return text.toLowerCase().split(/\\W+/).filter(Boolean).reduce((map, word) => {\n    map.set(word, (map.get(word) || 0) + 1);\n    return map;\n  }, new Map());\n}\nfunction uniqueVisitors(logs) {\n  const seen = new Set();\n  return logs.filter(log => {\n    if (seen.has(log.userId)) return false;\n    seen.add(log.userId);\n    return true;\n  });\n}\nconst topWords = (freq, n) => [...freq.entries()].sort((a,b)=>b[1]-a[1]).slice(0,n);",hints:"Map.get returns undefined for missing keys - use || 0 as default. Set.has is O(1). Spread Map.entries() for sorting.",solutionExplanation:"Map outperforms Object for frequent additions. Set provides O(1) membership testing. Both maintain insertion order."},
  {lessonId:26,difficulty:"Hard",topic:"ES6+ Features",title:"Iterable Class",problemStatement:"Make a Range class iterable by implementing [Symbol.iterator](). It should work with for-of, spread, and destructuring.",examples:"[...new Range(1,5)] === [1,2,3,4,5]. for(const n of new Range(0,10,2)) yields even numbers.",starterCodeJs:"class Range {\n  constructor(start, end, step = 1) {\n    this.start = start; this.end = end; this.step = step;\n  }\n  [Symbol.iterator]() {\n    let current = this.start;\n    const { end, step } = this;\n    return {\n      next() {\n        if (current <= end) {\n          const value = current;\n          current += step;\n          return { value, done: false };\n        }\n        return { value: undefined, done: true };\n      },\n      [Symbol.iterator]() { return this; } // make iterator itself iterable\n    };\n  }\n  toArray() { return [...this]; }\n}\nconsole.log([...new Range(1, 5)]); // [1,2,3,4,5]",hints:"[Symbol.iterator]() returns an iterator object with next(). next() returns {value, done}. done:true signals end.",solutionExplanation:"Implementing [Symbol.iterator] makes objects work with for-of, spread, and Array.from. Iterator must return {value, done}."},
  {lessonId:26,difficulty:"Medium",topic:"ES6+ Features",title:"Reflect API Usage",problemStatement:"Use the Reflect API to safely get/set properties, check existence, and delete. Demonstrate how Reflect works with Proxy as a safe forwarding mechanism.",examples:"Reflect.get(obj,key) vs obj[key]. Reflect.has(obj,key) vs key in obj.",starterCodeJs:"function createLoggingProxy(target) {\n  return new Proxy(target, {\n    get(t, prop, receiver) {\n      console.log(`GET ${prop}`);\n      return Reflect.get(t, prop, receiver); // forwarding with Reflect\n    },\n    set(t, prop, value, receiver) {\n      console.log(`SET ${prop} = ${JSON.stringify(value)}`);\n      return Reflect.set(t, prop, value, receiver);\n    },\n    has(t, prop) { console.log(`HAS ${prop}`); return Reflect.has(t, prop); },\n    deleteProperty(t, prop) { console.log(`DELETE ${prop}`); return Reflect.deleteProperty(t, prop); }\n  });\n}",hints:"Reflect methods mirror Proxy traps. Using Reflect in Proxy handlers ensures correct behavior with inheritance and receivers.",solutionExplanation:"Reflect provides a safe way to invoke default object operations in Proxy handlers. Always use Reflect instead of direct operations in Proxy traps."},
  {lessonId:26,difficulty:"Easy",topic:"ES6+ Features",title:"Optional Chaining and Nullish",problemStatement:"Demonstrate optional chaining and nullish coalescing for safe data access. Show how they replace verbose null checks.",examples:"user?.address?.city ?? 'Unknown' replaces if(user && user.address && user.address.city)",starterCodeJs:"function safeAccess(data) {\n  // Old way\n  const oldCity = data && data.user && data.user.address ? data.user.address.city : 'Unknown';\n  // New way\n  const city = data?.user?.address?.city ?? 'Unknown';\n  // Optional method call\n  const upper = data?.user?.name?.toUpperCase?.() ?? 'ANONYMOUS';\n  // Optional array access\n  const first = data?.items?.[0]?.name ?? 'No items';\n  // Nullish vs OR\n  const count = data?.count ?? 0; // ?? keeps 0 and ''\n  const countOr = data?.count || 0; // || replaces 0 and '' too\n  return {city, upper, first, count};\n}",hints:"?. short-circuits to undefined if left side is null/undefined. ?? only checks for null/undefined (not 0, '', false).",solutionExplanation:"?? vs ||: 0 ?? 'default' = 0 (0 is valid). 0 || 'default' = 'default' (0 is falsy). Use ?? for optional values."},
  {lessonId:26,difficulty:"Hard",topic:"ES6+ Features",title:"Async Generator Stream",problemStatement:"Create an async generator that reads a stream of data in chunks and yields processed lines. Simulate reading a large file line by line.",examples:"for await (const line of readLines(stream)) processes each line as it arrives",starterCodeJs:"async function* readLines(asyncIterable) {\n  let buffer = '';\n  for await (const chunk of asyncIterable) {\n    buffer += chunk;\n    const lines = buffer.split('\\n');\n    buffer = lines.pop(); // last incomplete line\n    for (const line of lines) if (line.trim()) yield line;\n  }\n  if (buffer.trim()) yield buffer; // remaining\n}\nasync function* simulateStream(data, chunkSize = 10) {\n  for (let i = 0; i < data.length; i += chunkSize) {\n    yield data.slice(i, i + chunkSize);\n    await new Promise(r => setTimeout(r, 10));\n  }\n}",hints:"Buffer handles chunks that don't align with line boundaries. split('\\n').pop() gives incomplete last chunk.",solutionExplanation:"Async generators + for-await-of enable memory-efficient streaming. Buffer prevents partial lines from being yielded prematurely."},

  // Lesson 27 - Prototypes and Classes
  {lessonId:27,difficulty:"Easy",topic:"Prototypes and Classes",title:"Class Inheritance Chain",problemStatement:"Build an Animal -> Mammal -> Dog inheritance chain using classes. Each class adds specific properties and methods. Show how super() and method overriding works.",examples:"new Dog('Rex').speak() calls Dog's speak(). new Dog('Rex').breathe() inherited from Mammal.",starterCodeJs:"class Animal {\n  constructor(name) { this.name = name; }\n  speak() { return `${this.name} makes a sound`; }\n  toString() { return `[Animal: ${this.name}]`; }\n}\nclass Mammal extends Animal {\n  constructor(name) { super(name); this.warmBlooded = true; }\n  breathe() { return `${this.name} breathes air`; }\n}\nclass Dog extends Mammal {\n  constructor(name, breed) { super(name); this.breed = breed; }\n  speak() { return `${this.name} says: Woof!`; } // override\n  fetch() { return `${this.name} fetches the ball`; }\n}\nconst d = new Dog('Rex','Labrador');\nconsole.log(d.speak());   // Rex says: Woof!\nconsole.log(d.breathe()); // Rex breathes air (inherited)\nconsole.log(d instanceof Animal); // true",hints:"super(name) calls parent constructor. super.method() calls parent method. instanceof checks prototype chain.",solutionExplanation:"ES6 class syntax hides prototype-based inheritance. Under the hood: Dog.prototype.__proto__ === Mammal.prototype."},
  {lessonId:27,difficulty:"Medium",topic:"Prototypes and Classes",title:"Mixin Composition",problemStatement:"Implement mixins to compose behaviors (Flyable, Swimmable, Runnable) into classes without deep inheritance hierarchies.",examples:"class Duck extends Swimmable(Flyable(Animal)) adds swimming and flying.",starterCodeJs:"const Flyable = (Base) => class extends Base {\n  fly() { return `${this.name} is flying`; }\n  get maxAltitude() { return 1000; }\n};\nconst Swimmable = (Base) => class extends Base {\n  swim() { return `${this.name} is swimming`; }\n  get swimSpeed() { return 5; }\n};\nconst Runnable = (Base) => class extends Base {\n  run(speed = 10) { return `${this.name} runs at ${speed}mph`; }\n};\nclass Animal { constructor(name) { this.name = name; } }\nclass Duck extends Swimmable(Flyable(Animal)) {\n  quack() { return `${this.name} says quack`; }\n}\nconst d = new Duck('Donald');\nconsole.log(d.fly());   // Donald is flying\nconsole.log(d.swim());  // Donald is swimming",hints:"Mixin function takes Base class and returns extended class. Compose by nesting: Mixin2(Mixin1(Base)).",solutionExplanation:"Mixins solve multiple inheritance. Each mixin is a function that extends any base class, enabling composition over inheritance."},
  {lessonId:27,difficulty:"Hard",topic:"Prototypes and Classes",title:"Private Fields and Methods",problemStatement:"Refactor a User class to use private fields (#) for sensitive data. Add private methods for validation. Show the class cannot be monkey-patched.",examples:"user.#password is SyntaxError. user.getEmail() works. Private #validateEmail()",starterCodeJs:"class User {\n  #email;\n  #password;\n  #loginAttempts = 0;\n  static #MAX_ATTEMPTS = 5;\n  constructor(email, password) {\n    this.#email = this.#validateEmail(email);\n    this.#password = this.#hashPassword(password);\n  }\n  #validateEmail(email) {\n    if (!/^[^@]+@[^@]+\\.[^@]+$/.test(email)) throw new Error('Invalid email');\n    return email.toLowerCase();\n  }\n  #hashPassword(pw) { return btoa(pw); } // simplified\n  login(email, password) {\n    if (this.#loginAttempts >= User.#MAX_ATTEMPTS) throw new Error('Account locked');\n    if (email === this.#email && btoa(password) === this.#password) {\n      this.#loginAttempts = 0;\n      return true;\n    }\n    this.#loginAttempts++;\n    return false;\n  }\n  getEmail() { return this.#email; }\n}",hints:"# prefix creates truly private fields. Cannot be accessed outside class body. Static private fields exist on the class itself.",solutionExplanation:"Private class fields (#) are syntax-enforced privacy unlike _convention. SyntaxError if accessed outside class body."},
  {lessonId:27,difficulty:"Medium",topic:"Prototypes and Classes",title:"Prototype Chain Inspector",problemStatement:"Write a function that visualizes the prototype chain of any object, showing each level's constructor name and own properties.",examples:"inspectChain(new Dog()) shows Dog -> Mammal -> Animal -> Object -> null",starterCodeJs:"function inspectChain(obj) {\n  const chain = [];\n  let current = obj;\n  while (current !== null) {\n    chain.push({\n      name: current.constructor?.name || 'Anonymous',\n      ownProps: Object.getOwnPropertyNames(current).filter(k => k !== '__proto__'),\n      isProto: current !== obj\n    });\n    current = Object.getPrototypeOf(current);\n  }\n  chain.push({ name: 'null', ownProps: [], isProto: true });\n  return chain;\n}\nfunction inheritsFrom(instance, Constructor) {\n  return Constructor.prototype.isPrototypeOf(instance);\n}",hints:"Object.getPrototypeOf walks up the chain. getOwnPropertyNames lists all own properties (enumerable and non-enumerable).",solutionExplanation:"Object.getPrototypeOf is the standard way to walk the chain. Continue until null (end of chain)."},
  {lessonId:27,difficulty:"Easy",topic:"Prototypes and Classes",title:"Static Factory Methods",problemStatement:"Implement a Color class with static factory methods: fromRGB(), fromHex(), fromHSL(). Each returns a Color instance and validates input.",examples:"Color.fromHex('#3b82f6').toRGB() returns {r:59,g:130,b:246}",starterCodeJs:"class Color {\n  constructor(r, g, b) {\n    if ([r,g,b].some(v => v < 0 || v > 255)) throw new RangeError('RGB values must be 0-255');\n    this.r = Math.round(r); this.g = Math.round(g); this.b = Math.round(b);\n  }\n  static fromHex(hex) {\n    const clean = hex.replace('#','');\n    return new Color(parseInt(clean.slice(0,2),16), parseInt(clean.slice(2,4),16), parseInt(clean.slice(4,6),16));\n  }\n  static fromRGB(r,g,b) { return new Color(r,g,b); }\n  toHex() { return '#' + [this.r,this.g,this.b].map(v=>v.toString(16).padStart(2,'0')).join(''); }\n  toCSS() { return `rgb(${this.r},${this.g},${this.b})`; }\n  mix(other, t=0.5) { return new Color(this.r*(1-t)+other.r*t, this.g*(1-t)+other.g*t, this.b*(1-t)+other.b*t); }\n}",hints:"Static factory methods are named constructors. They validate before calling new Color(). padStart(2,'0') zero-pads hex digits.",solutionExplanation:"Static factory methods provide named construction (fromHex is clearer than new Color with hex parsing logic)."},
  {lessonId:27,difficulty:"Hard",topic:"Prototypes and Classes",title:"Observable Class with Proxy",problemStatement:"Create an observable base class that uses Proxy to automatically notify subscribers when any property changes.",examples:"user.name = 'Alice' fires subscribers with {prop:'name', old:'Bob', new:'Alice'}",starterCodeJs:"class Observable {\n  #subscribers = new Map();\n  constructor() {\n    return new Proxy(this, {\n      set: (target, prop, value) => {\n        if (prop.startsWith('#') || prop.startsWith('_')) { target[prop] = value; return true; }\n        const old = target[prop];\n        target[prop] = value;\n        if (old !== value) this.#notify(prop, old, value);\n        return true;\n      }\n    });\n  }\n  #notify(prop, oldVal, newVal) {\n    (this.#subscribers.get(prop) || []).forEach(fn => fn({ prop, old: oldVal, new: newVal }));\n    (this.#subscribers.get('*') || []).forEach(fn => fn({ prop, old: oldVal, new: newVal }));\n  }\n  on(prop, fn) { if (!this.#subscribers.has(prop)) this.#subscribers.set(prop, []); this.#subscribers.get(prop).push(fn); return this; }\n  off(prop, fn) { const subs = this.#subscribers.get(prop); if (subs) { const i = subs.indexOf(fn); if (i > -1) subs.splice(i,1); } }\n}",hints:"Return new Proxy(this,...) from constructor. Proxy intercepts all property sets and notifies subscribers.",solutionExplanation:"Returning Proxy from constructor replaces 'this' with the proxy. All subsequent property access goes through the proxy."},
  {lessonId:27,difficulty:"Medium",topic:"Prototypes and Classes",title:"Class Decorator Pattern",problemStatement:"Implement decorator functions that add logging, timing, and retry behavior to class methods without modifying the class.",examples:"withLogging(UserService, 'getUser') wraps getUser with before/after logging",starterCodeJs:"function withLogging(instance, methodName) {\n  const original = instance[methodName].bind(instance);\n  instance[methodName] = async function(...args) {\n    console.log(`[${methodName}] called with`, args);\n    const start = Date.now();\n    try {\n      const result = await original(...args);\n      console.log(`[${methodName}] resolved in ${Date.now()-start}ms`);\n      return result;\n    } catch(e) {\n      console.error(`[${methodName}] failed:`, e.message);\n      throw e;\n    }\n  };\n  return instance;\n}\nfunction withRetry(instance, methodName, maxAttempts = 3) {\n  const original = instance[methodName].bind(instance);\n  instance[methodName] = async function(...args) {\n    for (let i = 0; i < maxAttempts; i++) {\n      try { return await original(...args); }\n      catch(e) { if (i === maxAttempts-1) throw e; await new Promise(r=>setTimeout(r, 1000*Math.pow(2,i))); }\n    }\n  };\n  return instance;\n}",hints:"Store original method with bind. Replace method on instance. Call original in the wrapper. Return instance for chaining.",solutionExplanation:"Method decoration wraps functions without modifying the class. Bind preserves 'this' context when storing the original."},
  {lessonId:27,difficulty:"Easy",topic:"Prototypes and Classes",title:"toString and valueOf Override",problemStatement:"Override toString() and valueOf() on a Money class so it works naturally in string and numeric contexts.",examples:"new Money(10,'USD') + ' cost' -> '$10.00 USD cost'. +new Money(10) -> 10",starterCodeJs:"class Money {\n  constructor(amount, currency = 'USD') {\n    this.amount = amount; this.currency = currency;\n  }\n  toString() { return `$${this.amount.toFixed(2)} ${this.currency}`; }\n  valueOf() { return this.amount; } // enables numeric operations\n  [Symbol.toPrimitive](hint) {\n    if (hint === 'number') return this.amount;\n    if (hint === 'string') return this.toString();\n    return this.amount; // default\n  }\n  add(other) { return new Money(this.amount + +other, this.currency); }\n  static format(amount, currency = 'USD') { return new Money(amount, currency).toString(); }\n}\nconsole.log(`Cost: ${new Money(10.5)}`); // Cost: $10.50 USD\nconsole.log(new Money(10) + new Money(5)); // 15 (via valueOf)",hints:"valueOf enables numeric context. toString enables string context. Symbol.toPrimitive gives full control over conversion hints.",solutionExplanation:"Symbol.toPrimitive is the modern way to control type coercion. hint is 'number', 'string', or 'default'."},
  {lessonId:27,difficulty:"Hard",topic:"Prototypes and Classes",title:"Class Without new Keyword",problemStatement:"Make a class that works both with and without the 'new' keyword. Also implement a class that is sealed after construction.",examples:"User('Alice') and new User('Alice') both work. Sealed class prevents adding new properties.",starterCodeJs:"function FlexibleUser(name) {\n  if (!(this instanceof FlexibleUser)) return new FlexibleUser(name);\n  this.name = name;\n}\nFlexibleUser.prototype.greet = function() { return `Hi, I'm ${this.name}`; };\nclass SealedUser {\n  constructor(name) {\n    this.name = name;\n    Object.seal(this); // prevents adding new props, allows changing existing\n  }\n  greet() { return `Hi, I'm ${this.name}`; }\n}\nconst u1 = FlexibleUser('Alice'); // works\nconst u2 = new FlexibleUser('Bob'); // works\nconst u3 = new SealedUser('Charlie');\nu3.age = 30; // silently fails (or throws in strict mode)",hints:"Check instanceof to detect missing new. Object.seal allows modification but not extension or deletion.",solutionExplanation:"instanceof check enables new-optional factories. Object.seal vs Object.freeze: seal allows value changes, freeze prevents all changes."},
  {lessonId:27,difficulty:"Medium",topic:"Prototypes and Classes",title:"Linked List Class",problemStatement:"Implement a singly linked list using classes with: append, prepend, delete, find, and toArray methods.",examples:"list.append(1).append(2).append(3).toArray() === [1,2,3]",starterCodeJs:"class Node { constructor(val) { this.val = val; this.next = null; } }\nclass LinkedList {\n  constructor() { this.head = null; this.size = 0; }\n  append(val) { const n = new Node(val); if (!this.head) this.head = n; else { let c = this.head; while(c.next) c=c.next; c.next = n; } this.size++; return this; }\n  prepend(val) { const n = new Node(val); n.next = this.head; this.head = n; this.size++; return this; }\n  delete(val) { if (!this.head) return; if (this.head.val===val) { this.head=this.head.next; this.size--; return; } let c=this.head; while(c.next && c.next.val!==val) c=c.next; if (c.next) { c.next=c.next.next; this.size--; } }\n  toArray() { const a=[]; let c=this.head; while(c) { a.push(c.val); c=c.next; } return a; }\n  [Symbol.iterator]() { let c=this.head; return { next() { if(c) {const v=c.val; c=c.next; return {value:v,done:false};} return {done:true}; } }; }\n}",hints:"Traverse with while(c.next) to find tail. To delete: find the node before target, relink next pointers.",solutionExplanation:"Linked list: O(1) prepend, O(n) append/find/delete. Implementing [Symbol.iterator] makes it usable in for-of and spread."},

  // Lesson 28 - Error Handling
  {lessonId:28,difficulty:"Easy",topic:"Error Handling",title:"Custom Error Classes",problemStatement:"Create a hierarchy of custom error classes: AppError base, ValidationError, NetworkError, AuthError. Each should have code and context.",examples:"throw new ValidationError('Invalid email', {field:'email'}) caught with instanceof ValidationError",starterCodeJs:"class AppError extends Error {\n  constructor(message, code, context = {}) {\n    super(message);\n    this.name = this.constructor.name;\n    this.code = code;\n    this.context = context;\n    if (Error.captureStackTrace) Error.captureStackTrace(this, this.constructor);\n  }\n  toJSON() { return { name: this.name, message: this.message, code: this.code, context: this.context }; }\n}\nclass ValidationError extends AppError { constructor(msg, ctx) { super(msg, 'VALIDATION_ERROR', ctx); } }\nclass NetworkError extends AppError { constructor(msg, ctx) { super(msg, 'NETWORK_ERROR', ctx); } }\nclass AuthError extends AppError { constructor(msg, ctx) { super(msg, 'AUTH_ERROR', ctx); } }",hints:"Set this.name in constructor for correct name in stack traces. captureStackTrace removes the constructor from the trace.",solutionExplanation:"Custom error hierarchy enables targeted catch blocks and structured error handling. toJSON enables error serialization for logging."},
  {lessonId:28,difficulty:"Medium",topic:"Error Handling",title:"Result Type Pattern",problemStatement:"Implement a Result type (Ok/Err) for explicit error handling without try/catch. Similar to Rust's Result enum.",examples:"const result = fetchUser(id); if(result.ok) use(result.value); else handleError(result.error)",starterCodeJs:"const Ok = (value) => ({ ok: true, value, map: fn => Ok(fn(value)), flatMap: fn => fn(value), match: ({ok}) => ok(value) });\nconst Err = (error) => ({ ok: false, error, map: () => Err(error), flatMap: () => Err(error), match: ({err}) => err(error) });\nasync function safeAsync(fn) {\n  try { return Ok(await fn()); }\n  catch(e) { return Err(e); }\n}\n// Usage\nasync function getUser(id) {\n  return safeAsync(() => fetch(`/api/users/${id}`).then(r => r.json()));\n}\nconst result = await getUser(1);\nresult.match({\n  ok: user => displayUser(user),\n  err: error => showError(error)\n});",hints:"Result is either Ok(value) or Err(error). map applies function only on Ok. flatMap enables chaining operations that return Results.",solutionExplanation:"Result type makes errors explicit in type signatures. No unexpected exceptions. Popular in functional programming (fp-ts, neverthrow)."},
  {lessonId:28,difficulty:"Medium",topic:"Error Handling",title:"Error Boundary HOC",problemStatement:"Write an error boundary wrapper for async operations that logs errors, reports to monitoring, and returns a fallback value.",examples:"withErrorBoundary(riskyFn, {fallback:null, report:true}) returns null on failure",starterCodeJs:"function withErrorBoundary(fn, { fallback = null, report = true, context = {} } = {}) {\n  return async function(...args) {\n    try {\n      return await fn(...args);\n    } catch(error) {\n      if (report) logError(error, { fn: fn.name, args, context });\n      return fallback;\n    }\n  };\n}\nfunction logError(error, context) {\n  console.error(JSON.stringify({ timestamp: new Date().toISOString(), name: error.name, message: error.message, context }));\n  // In production: send to Sentry, Datadog, etc.\n}\nconst safeGetUser = withErrorBoundary(getUser, { fallback: null, context: { service: 'user-api' } });",hints:"Wrap async function in try/catch. Use fallback value on catch. Log with structured context for debugging.",solutionExplanation:"Error boundaries prevent crashes by substituting fallback values. Structured logging includes context for production debugging."},
  {lessonId:28,difficulty:"Hard",topic:"Error Handling",title:"Async Error Chain",problemStatement:"Build an async pipeline that collects errors from multiple steps without short-circuiting. Return all errors and successful results.",examples:"runAll([stepA, stepB, stepC]) returns {results:[], errors:[]} even if some steps fail",starterCodeJs:"async function runAll(tasks, { bail = false } = {}) {\n  const results = [];\n  const errors = [];\n  for (let i = 0; i < tasks.length; i++) {\n    try {\n      results.push({ index: i, value: await tasks[i]() });\n    } catch(e) {\n      errors.push({ index: i, error: e });\n      if (bail) break;\n    }\n  }\n  return { results, errors, allPassed: errors.length === 0 };\n}\nasync function runAllParallel(tasks) {\n  const settled = await Promise.allSettled(tasks.map(t => t()));\n  return settled.reduce((acc, r, i) => {\n    if (r.status === 'fulfilled') acc.results.push({index:i, value:r.value});\n    else acc.errors.push({index:i, error:r.reason});\n    return acc;\n  }, {results:[], errors:[]});\n}",hints:"Promise.allSettled never rejects. Sequential: catch per step, collect errors. bail option for short-circuit behavior.",solutionExplanation:"Collecting all errors (not just first) enables reporting all validation failures at once. allSettled is perfect for parallel case."},
  {lessonId:28,difficulty:"Easy",topic:"Error Handling",title:"Safe JSON Parse",problemStatement:"Write a safe JSON parser that returns a Result (not throws). Also write a safe JSON stringify with circular reference handling.",examples:"safeParseJSON('invalid') returns {ok:false, error}. safeStringify(obj) handles circular refs.",starterCodeJs:"function safeParseJSON(str, fallback = null) {\n  try { return { ok: true, value: JSON.parse(str) }; }\n  catch(e) { return { ok: false, error: e.message, fallback }; }\n}\nfunction safeStringify(obj, indent = 2) {\n  const seen = new WeakSet();\n  try {\n    return JSON.stringify(obj, (key, val) => {\n      if (typeof val === 'object' && val !== null) {\n        if (seen.has(val)) return '[Circular]';\n        seen.add(val);\n      }\n      return val;\n    }, indent);\n  } catch(e) { return null; }\n}",hints:"JSON.parse throws on invalid JSON. WeakSet tracks visited objects for circular reference detection in replacer.",solutionExplanation:"Safe wrappers prevent uncaught exceptions. Circular reference handling is needed for stringify since JSON.stringify throws on cycles."},
  {lessonId:28,difficulty:"Medium",topic:"Error Handling",title:"Global Error Handler",problemStatement:"Set up comprehensive global error handling for both synchronous errors and unhandled promise rejections. Include source maps and context.",examples:"window.onerror + window.onunhandledrejection + structured logging to endpoint",starterCodeJs:"function setupGlobalErrorHandling({ endpoint, appVersion, userId } = {}) {\n  function report(data) {\n    if (!endpoint) return console.error('Error:', data);\n    fetch(endpoint, { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(data) }).catch(() => {});\n  }\n  window.addEventListener('error', (e) => {\n    report({ type:'error', message:e.message, filename:e.filename, line:e.lineno, col:e.colno, stack:e.error?.stack, appVersion, userId, time:Date.now() });\n  });\n  window.addEventListener('unhandledrejection', (e) => {\n    report({ type:'unhandledrejection', message:e.reason?.message || String(e.reason), stack:e.reason?.stack, appVersion, userId, time:Date.now() });\n    e.preventDefault(); // suppress console warning\n  });\n}",hints:"error event fires for uncaught synchronous errors. unhandledrejection fires for unhandled Promise rejections. report fires and forgets.",solutionExplanation:"Global handlers are the last defense. They capture errors that escape all local try/catch. Use for monitoring dashboards."},
  {lessonId:28,difficulty:"Hard",topic:"Error Handling",title:"Validation Schema",problemStatement:"Build a validation schema system with composable validators. Support: required, minLength, maxLength, pattern, and custom validators.",examples:"schema.validate({name:'', age:-1}) returns [{field:'name',error:'required'},{field:'age',error:'min:0'}]",starterCodeJs:"const validators = {\n  required: () => v => v != null && v !== '' || 'Required',\n  minLength: n => v => !v || v.length >= n || `Min ${n} chars`,\n  maxLength: n => v => !v || v.length <= n || `Max ${n} chars`,\n  min: n => v => v == null || +v >= n || `Min value: ${n}`,\n  max: n => v => v == null || +v <= n || `Max value: ${n}`,\n  pattern: r => v => !v || r.test(v) || `Invalid format`,\n  email: () => validators.pattern(/^[^@]+@[^@]+\\.[^@]+$/)()\n};\nclass Schema {\n  constructor(rules) { this.rules = rules; }\n  validate(data) {\n    return Object.entries(this.rules).flatMap(([field, fieldRules]) =>\n      fieldRules.map(rule => ({ field, result: rule(data[field]) })).filter(r => r.result !== true).map(r => ({ field: r.field, error: r.result }))\n    );\n  }\n}",hints:"Validators are curried: validators.minLength(3) returns a validator function. flatMap collects all errors across all fields.",solutionExplanation:"Composable validators can be combined per field. Return true for valid, error message string for invalid."},
  {lessonId:28,difficulty:"Easy",topic:"Error Handling",title:"Try/Catch Best Practices",problemStatement:"Demonstrate correct try/catch patterns: catch specific errors, don't swallow, always rethrow unknown errors, log with context.",examples:"catch(e) { if(e instanceof NetworkError) retry(); else throw e; }",starterCodeJs:"async function fetchUserSafely(id) {\n  try {\n    const res = await fetch(`/api/users/${id}`);\n    if (!res.ok) throw new NetworkError(`HTTP ${res.status}`, { status: res.status, id });\n    return await res.json();\n  } catch(e) {\n    if (e instanceof NetworkError && e.code === 'NETWORK_ERROR') {\n      console.warn('Network error, returning cached data');\n      return getCached(id);\n    }\n    // Unknown error - log and rethrow\n    console.error('Unexpected error in fetchUserSafely:', e);\n    throw e; // Don't swallow!\n  }\n}\nfunction getCached(id) { return null; }",hints:"Only catch errors you can handle. Rethrow unknown errors. Log before rethrowing for debugging context.",solutionExplanation:"Swallowing errors causes silent failures. Always rethrow if you cannot handle. Log before rethrowing adds context without swallowing."},
  {lessonId:28,difficulty:"Hard",topic:"Error Handling",title:"Circuit Breaker Pattern",problemStatement:"Implement a Circuit Breaker that stops calling a failing service after N failures and retries after a timeout.",examples:"breaker.call(fn): 5 failures -> OPEN (fail fast) -> after 30s -> HALF_OPEN -> test -> CLOSED",starterCodeJs:"class CircuitBreaker {\n  constructor(fn, { threshold=5, timeout=30000 } = {}) {\n    this.fn = fn; this.threshold = threshold; this.timeout = timeout;\n    this.failures = 0; this.state = 'CLOSED'; this.nextAttempt = 0;\n  }\n  async call(...args) {\n    if (this.state === 'OPEN') {\n      if (Date.now() < this.nextAttempt) throw new Error('Circuit OPEN - service unavailable');\n      this.state = 'HALF_OPEN';\n    }\n    try {\n      const result = await this.fn(...args);\n      if (this.state === 'HALF_OPEN') { this.failures = 0; this.state = 'CLOSED'; }\n      this.failures = 0;\n      return result;\n    } catch(e) {\n      this.failures++;\n      if (this.failures >= this.threshold) { this.state = 'OPEN'; this.nextAttempt = Date.now() + this.timeout; }\n      throw e;\n    }\n  }\n}",hints:"CLOSED: normal. OPEN: fail fast. HALF_OPEN: one test request. Timeout determines when to try again.",solutionExplanation:"Circuit breaker prevents cascading failures. After threshold failures, it opens and fails fast until timeout, then tests with one request."},
  {lessonId:28,difficulty:"Medium",topic:"Error Handling",title:"Error Context Enricher",problemStatement:"Write a middleware function that enriches errors with request context before they propagate, making debugging easier.",examples:"withContext(fn, {requestId, userId}) - errors from fn include this context",starterCodeJs:"function withContext(fn, context) {\n  return async function(...args) {\n    try {\n      return await fn(...args);\n    } catch(error) {\n      error.context = { ...(error.context || {}), ...context };\n      error.message = `[${Object.entries(context).map(([k,v])=>`${k}:${v}`).join(',')}] ${error.message}`;\n      throw error;\n    }\n  };\n}\nfunction createRequestLogger(req) {\n  return {\n    requestId: req.headers['x-request-id'] || Math.random().toString(36).slice(2),\n    method: req.method,\n    path: req.path,\n    userId: req.user?.id\n  };\n}",hints:"Mutate the error object to add context before rethrowing. Context in error message makes log searching possible.",solutionExplanation:"Enriching errors with context (request ID, user ID) enables tracing an error through distributed systems."},

  // Lesson 29 - Modules
  {lessonId:29,difficulty:"Easy",topic:"JS Modules",title:"Named vs Default Exports",problemStatement:"Create a utility module with both named exports and a default export. Show how to import them individually, all-named, renamed, and the default.",examples:"import defaultFn, {util1, util2 as alias} from './utils'",starterCodeJs:"// utils.js\nexport const add = (a, b) => a + b;\nexport const multiply = (a, b) => a * b;\nexport function formatDate(date) { return date.toISOString().split('T')[0]; }\nexport default class MathUtils {\n  static sum(...nums) { return nums.reduce((a,b) => a+b, 0); }\n  static average(...nums) { return MathUtils.sum(...nums) / nums.length; }\n}\n// consumer.js\nimport MathUtils, { add, multiply, formatDate as fmt } from './utils.js';\nimport * as utils from './utils.js';\nconsole.log(add(1,2));          // 3\nconsole.log(utils.multiply(2,3)); // 6\nconsole.log(MathUtils.sum(1,2,3)); // 6",hints:"Default export: one per module, import as any name. Named exports: many per module, import by name with {}.",solutionExplanation:"import * as namespace imports all named exports as properties. default is accessed as namespace.default."},
  {lessonId:29,difficulty:"Medium",topic:"JS Modules",title:"Dynamic Import Code Splitting",problemStatement:"Implement code splitting using dynamic import(). Load a heavy chart library only when the user navigates to the analytics page.",examples:"const {Chart} = await import('./chart.js') on route change to /analytics",starterCodeJs:"const routes = {\n  '/': () => import('./pages/home.js'),\n  '/analytics': () => import('./pages/analytics.js'),\n  '/settings': () => import('./pages/settings.js')\n};\nasync function navigate(path) {\n  const loader = routes[path];\n  if (!loader) { console.error('404'); return; }\n  const module = await loader();\n  const page = module.default || module;\n  document.getElementById('app').innerHTML = '';\n  page.render(document.getElementById('app'));\n}\nwindow.addEventListener('popstate', () => navigate(location.pathname));\nnavigate(location.pathname);",hints:"import() returns a Promise that resolves to the module object. Defer non-critical imports until needed.",solutionExplanation:"Dynamic imports enable code splitting - each route loads only its code. Reduces initial bundle and time-to-interactive."},
  {lessonId:29,difficulty:"Medium",topic:"JS Modules",title:"Module Singleton Pattern",problemStatement:"Demonstrate how ES modules are natural singletons. Create a config module and show the same instance is reused across imports.",examples:"Two files importing config.js get the same object. Mutating it in one file is visible in another.",starterCodeJs:"// config.js - loaded once, same instance shared\nconst config = {\n  apiUrl: process.env.API_URL || 'http://localhost:3000',\n  debug: process.env.NODE_ENV !== 'production',\n  maxRetries: 3\n};\nlet initialized = false;\nexport function init(overrides = {}) {\n  if (initialized) throw new Error('Config already initialized');\n  Object.assign(config, overrides);\n  initialized = true;\n}\nexport function get(key) { return config[key]; }\nexport function getAll() { return { ...config }; } // return copy, not reference",hints:"Module scope is created once and reused. The module object is cached after first import. Mutation is visible to all importers.",solutionExplanation:"ES module singleton: any state in module scope is shared. Export functions instead of mutable data to control access."},
  {lessonId:29,difficulty:"Hard",topic:"JS Modules",title:"Plugin System with Modules",problemStatement:"Build a plugin system where plugins are ES modules that self-register. Core exposes register() and execute() API.",examples:"plugins/logger.js calls core.register('logger', handler). core.execute('logger') calls it.",starterCodeJs:"// core.js\nconst plugins = new Map();\nexport function register(name, handler, options = {}) {\n  if (plugins.has(name)) throw new Error(`Plugin '${name}' already registered`);\n  plugins.set(name, { handler, options, enabled: true });\n}\nexport async function execute(name, ...args) {\n  const plugin = plugins.get(name);\n  if (!plugin || !plugin.enabled) throw new Error(`Plugin '${name}' not found or disabled`);\n  return plugin.handler(...args);\n}\nexport function disable(name) { if (plugins.has(name)) plugins.get(name).enabled = false; }\nexport function list() { return [...plugins.entries()].map(([name, p]) => ({name, enabled: p.enabled})); }",hints:"Map stores plugins by name. Each plugin registers itself on import. execute() looks up and calls the handler.",solutionExplanation:"Plugin systems use a registry pattern. Modules self-register on import, decoupling plugin loading from plugin configuration."},
  {lessonId:29,difficulty:"Easy",topic:"JS Modules",title:"Re-exporting and Barrel Files",problemStatement:"Create a barrel file (index.js) that re-exports from multiple sub-modules, creating a unified public API.",examples:"import {Button, Input, Modal} from './components' imports from components/index.js barrel",starterCodeJs:"// components/button.js\nexport const Button = () => '<button>';\nexport const IconButton = () => '<button class=icon>';\n// components/input.js\nexport const Input = () => '<input>';\nexport const Textarea = () => '<textarea>';\n// components/index.js (barrel)\nexport { Button, IconButton } from './button.js';\nexport { Input, Textarea } from './input.js';\nexport { Modal, Dialog } from './modal.js';\n// Or export everything:\n// export * from './button.js';\n// Consumer:\nimport { Button, Input } from './components/index.js';",hints:"export {name} from './module' re-exports. export * re-exports all named exports. Barrel files simplify import paths.",solutionExplanation:"Barrel files create package-like APIs. Downside: may prevent tree shaking if not careful. Add sideEffects:false in package.json."},
  {lessonId:29,difficulty:"Medium",topic:"JS Modules",title:"CommonJS to ESM Migration",problemStatement:"Convert a CommonJS module to ESM. Handle: require(), module.exports, __dirname, __filename, and conditional imports.",examples:"require() -> import. module.exports = {} -> export default {}. __dirname via import.meta.url",starterCodeJs:"// CommonJS version\nconst path = require('path');\nconst fs = require('fs');\nconst { EventEmitter } = require('events');\nmodule.exports = class FileWatcher extends EventEmitter {\n  constructor(dir) { super(); this.dir = path.resolve(dir); }\n  watch() { fs.watch(this.dir, (e,f) => this.emit('change',{event:e,file:f})); }\n};\n// ESM equivalent\nimport path from 'path';\nimport fs from 'fs';\nimport { EventEmitter } from 'events';\nimport { fileURLToPath } from 'url';\nconst __dirname = path.dirname(fileURLToPath(import.meta.url));\nexport default class FileWatcher extends EventEmitter {\n  constructor(dir) { super(); this.dir = path.resolve(__dirname, dir); }\n  watch() { fs.watch(this.dir, (e,f) => this.emit('change',{event:e,file:f})); }\n}",hints:"fileURLToPath(import.meta.url) gives __filename equivalent. path.dirname gives __dirname. .mjs extension or type:module in package.json.",solutionExplanation:"import.meta.url is the ESM equivalent of __filename. Dynamic require() becomes dynamic import(). Node.js supports both."},
  {lessonId:29,difficulty:"Hard",topic:"JS Modules",title:"Module Federation Simulation",problemStatement:"Simulate module federation: a host app that dynamically loads a remote component from a URL at runtime.",examples:"loadRemote('http://remote/button.js', 'Button') fetches and uses remote component",starterCodeJs:"const remoteCache = new Map();\nasync function loadRemote(url, exportName) {\n  if (remoteCache.has(url)) {\n    const module = remoteCache.get(url);\n    return exportName ? module[exportName] : module;\n  }\n  const module = await import(/* webpackIgnore: true */ url);\n  remoteCache.set(url, module);\n  return exportName ? module[exportName] : module;\n}\nasync function renderRemoteComponent(url, exportName, props) {\n  try {\n    const Component = await loadRemote(url, exportName);\n    return Component(props);\n  } catch(e) {\n    console.error(`Failed to load remote ${exportName}:`, e);\n    return '<div>Failed to load component</div>';\n  }\n}",hints:"Dynamic import() can take a URL. Cache loaded modules to avoid re-fetching. webpackIgnore comment prevents bundler from processing.",solutionExplanation:"Module federation enables micro-frontends. Modules are loaded at runtime from separate deployments. Caching is essential."},
  {lessonId:29,difficulty:"Easy",topic:"JS Modules",title:"Tree Shaking Setup",problemStatement:"Structure a utility library for optimal tree shaking. Show what prevents tree shaking and how to fix it.",examples:"Named exports are tree-shakable. Side effects prevent tree shaking. sideEffects:false enables it.",starterCodeJs:"// Bad: default export object prevents tree shaking\nexport default {\n  add: (a,b) => a+b,\n  multiply: (a,b) => a*b,\n  // bundler can't know which methods are used\n};\n// Good: named exports are tree-shakable\nexport const add = (a,b) => a+b;\nexport const multiply = (a,b) => a*b;\nexport const format = (n, decimals=2) => n.toFixed(decimals);\n// package.json:\nconst packageJson = {\n  name: 'my-utils',\n  sideEffects: false, // enables tree shaking of entire module\n  module: 'dist/index.esm.js', // ESM entry for bundlers\n  main: 'dist/index.cjs.js'   // CJS for Node.js\n};",hints:"Named exports enable per-export tree shaking. sideEffects:false tells bundler no module has side effects. module field points to ESM build.",solutionExplanation:"Tree shaking requires: named exports, ESM format, no side effects. sideEffects:false is the most impactful change for library authors."},
  {lessonId:29,difficulty:"Medium",topic:"JS Modules",title:"Import Map Implementation",problemStatement:"Create an import map that maps bare module specifiers to URLs. Write the HTML and a runtime shim for environments that don't support import maps.",examples:"<script type=importmap> maps 'react' to CDN URL. Bare import 'react' works in browser.",starterCodeJs:"const importMap = {\n  imports: {\n    'react': 'https://esm.sh/react@18',\n    'react-dom/client': 'https://esm.sh/react-dom@18/client',\n    'lodash': 'https://esm.sh/lodash-es'\n  }\n};\nfunction injectImportMap(map) {\n  const script = document.createElement('script');\n  script.type = 'importmap';\n  script.textContent = JSON.stringify(map);\n  document.head.prepend(script); // must be before any module scripts\n}\nfunction importMapHTML(map) {\n  return `<script type='importmap'>${JSON.stringify(map, null, 2)}</script>`;\n}",hints:"Import map must be injected before any module scripts. prepend() ensures correct order. esm.sh is a CDN that serves ESM packages.",solutionExplanation:"Import maps standardize bare imports in browsers. Must appear before module scripts. Only one import map per document."},
  {lessonId:29,difficulty:"Hard",topic:"JS Modules",title:"Circular Dependency Resolver",problemStatement:"Write a function that detects circular dependencies in a module dependency graph represented as an adjacency list.",examples:"detectCycles({A:['B'], B:['C'], C:['A']}) returns [['A','B','C','A']]",starterCodeJs:"function detectCycles(graph) {\n  const cycles = [];\n  const visited = new Set();\n  const inStack = new Set();\n  const path = [];\n  function dfs(node) {\n    if (inStack.has(node)) {\n      const cycleStart = path.indexOf(node);\n      cycles.push([...path.slice(cycleStart), node]);\n      return;\n    }\n    if (visited.has(node)) return;\n    visited.add(node);\n    inStack.add(node);\n    path.push(node);\n    (graph[node] || []).forEach(dep => dfs(dep));\n    path.pop();\n    inStack.delete(node);\n  }\n  Object.keys(graph).forEach(node => { if (!visited.has(node)) dfs(node); });\n  return cycles;\n}",hints:"DFS with two sets: visited (done) and inStack (current path). Cycle detected when we revisit an inStack node.",solutionExplanation:"DFS cycle detection: inStack tracks current path. If we visit an inStack node, we found a cycle. Extract the cycle from the path."},

  // Lesson 30 - JS Patterns
  {lessonId:30,difficulty:"Easy",topic:"JavaScript Patterns",title:"Observer Pattern",problemStatement:"Implement a full EventEmitter class with on(), off(), once(), and emit() methods.",examples:"emitter.on('data', handler). emitter.emit('data', payload). emitter.once for one-time handlers.",starterCodeJs:"class EventEmitter {\n  constructor() { this._events = new Map(); }\n  on(event, fn) {\n    if (!this._events.has(event)) this._events.set(event, []);\n    this._events.get(event).push(fn);\n    return () => this.off(event, fn); // return unsubscribe fn\n  }\n  once(event, fn) {\n    const wrapper = (...args) => { this.off(event, wrapper); fn(...args); };\n    return this.on(event, wrapper);\n  }\n  off(event, fn) {\n    const fns = this._events.get(event);\n    if (fns) this._events.set(event, fns.filter(f => f !== fn));\n    return this;\n  }\n  emit(event, ...args) {\n    (this._events.get(event) || []).forEach(fn => fn(...args));\n    return this.has(event);\n  }\n  has(event) { return this._events.has(event) && this._events.get(event).length > 0; }\n  removeAll(event) { event ? this._events.delete(event) : this._events.clear(); }\n}",hints:"once() wraps the handler to remove itself after first call. on() returns an unsubscribe function for cleanup.",solutionExplanation:"EventEmitter is the core of Node.js. Returning unsubscribe from on() enables React-style cleanup: useEffect(() => emitter.on(...))."},
  {lessonId:30,difficulty:"Medium",topic:"JavaScript Patterns",title:"Pub/Sub with Namespaced Events",problemStatement:"Build a pub/sub system supporting namespaced events like 'user:login', 'user:logout', and wildcard subscriptions to 'user:*'.",examples:"pubsub.subscribe('user:*', handler) catches all user events. publish('user:login', data)",starterCodeJs:"class PubSub {\n  constructor() { this.subscribers = {}; }\n  subscribe(pattern, fn) {\n    if (!this.subscribers[pattern]) this.subscribers[pattern] = [];\n    this.subscribers[pattern].push(fn);\n    return () => this.unsubscribe(pattern, fn);\n  }\n  unsubscribe(pattern, fn) {\n    this.subscribers[pattern] = (this.subscribers[pattern] || []).filter(f => f !== fn);\n  }\n  publish(event, data) {\n    Object.entries(this.subscribers).forEach(([pattern, fns]) => {\n      if (this.matches(pattern, event)) fns.forEach(fn => fn(data, event));\n    });\n  }\n  matches(pattern, event) {\n    if (pattern === event) return true;\n    if (pattern.endsWith('*')) return event.startsWith(pattern.slice(0,-1));\n    return false;\n  }\n}",hints:"Wildcard matching: pattern ending in '*' matches events starting with the prefix. Check exact match first.",solutionExplanation:"Namespaced events improve organization. Wildcards enable cross-cutting concerns like logging all events in a namespace."},
  {lessonId:30,difficulty:"Medium",topic:"JavaScript Patterns",title:"Command Pattern with Undo",problemStatement:"Implement a command pattern for a text editor with undo/redo functionality. Each operation is a Command object.",examples:"editor.execute(new InsertCommand('Hello')). editor.undo() reverts. editor.redo() reapplies.",starterCodeJs:"class TextEditor {\n  constructor() { this.text = ''; this.history = []; this.future = []; }\n  execute(command) {\n    command.execute(this);\n    this.history.push(command);\n    this.future = []; // clear redo stack on new command\n  }\n  undo() {\n    const command = this.history.pop();\n    if (command) { command.undo(this); this.future.push(command); }\n  }\n  redo() {\n    const command = this.future.pop();\n    if (command) { command.execute(this); this.history.push(command); }\n  }\n}\nclass InsertCommand {\n  constructor(text, pos = 0) { this.text = text; this.pos = pos; }\n  execute(editor) { editor.text = editor.text.slice(0,this.pos) + this.text + editor.text.slice(this.pos); }\n  undo(editor) { editor.text = editor.text.slice(0,this.pos) + editor.text.slice(this.pos + this.text.length); }\n}",hints:"history stack for undo. future stack for redo. New command clears future stack. Both execute() and undo() mutate the editor state.",solutionExplanation:"Command pattern encapsulates operations as objects. Undo/redo becomes trivial: execute in reverse (undo) or re-execute (redo)."},
  {lessonId:30,difficulty:"Easy",topic:"JavaScript Patterns",title:"Factory Pattern",problemStatement:"Build a UI component factory that creates different component types (Button, Input, Modal) based on configuration, returning objects with render() and destroy() methods.",examples:"ComponentFactory.create({type:'button', label:'Click'}).render(container)",starterCodeJs:"class ComponentFactory {\n  static #registry = new Map();\n  static register(type, creator) { this.#registry.set(type, creator); }\n  static create(config) {\n    const creator = this.#registry.get(config.type);\n    if (!creator) throw new Error(`Unknown component type: ${config.type}`);\n    return creator(config);\n  }\n}\nComponentFactory.register('button', ({label, onClick}) => ({\n  el: null,\n  render(container) {\n    this.el = document.createElement('button');\n    this.el.textContent = label;\n    if (onClick) this.el.addEventListener('click', onClick);\n    container.appendChild(this.el);\n    return this;\n  },\n  destroy() { this.el?.remove(); }\n}));\nComponentFactory.register('input', ({placeholder, type='text'}) => ({\n  el: null,\n  render(container) { this.el = Object.assign(document.createElement('input'), {type, placeholder}); container.appendChild(this.el); return this; },\n  getValue() { return this.el?.value; },\n  destroy() { this.el?.remove(); }\n}));",hints:"Registry pattern stores creators by type. Factory delegates to registered creator. New types added by registering, not modifying Factory.",solutionExplanation:"Registry-based factory is open for extension: new component types registered without modifying ComponentFactory. Open/Closed Principle."},
  {lessonId:30,difficulty:"Hard",topic:"JavaScript Patterns",title:"State Machine",problemStatement:"Implement a finite state machine for a traffic light: RED->GREEN->YELLOW->RED. Prevent invalid transitions and fire transition callbacks.",examples:"light.transition('GO') in RED state -> GREEN. 'STOP' in RED state throws invalid transition.",starterCodeJs:"class StateMachine {\n  constructor({ initial, states, transitions }) {\n    this.current = initial;\n    this.states = states;\n    this.transitions = transitions;\n    this._listeners = [];\n  }\n  can(action) {\n    return this.transitions.some(t => t.from === this.current && t.on === action);\n  }\n  transition(action) {\n    const t = this.transitions.find(t => t.from === this.current && t.on === action);\n    if (!t) throw new Error(`Invalid transition '${action}' from '${this.current}'`);\n    const prev = this.current;\n    this.current = t.to;\n    this._listeners.forEach(fn => fn({ from: prev, to: this.current, action }));\n    return this;\n  }\n  onTransition(fn) { this._listeners.push(fn); return this; }\n}\nconst trafficLight = new StateMachine({\n  initial: 'RED',\n  states: ['RED','GREEN','YELLOW'],\n  transitions: [{from:'RED',on:'GO',to:'GREEN'},{from:'GREEN',on:'SLOW',to:'YELLOW'},{from:'YELLOW',on:'STOP',to:'RED'}]\n});",hints:"Find transition by current state and action. Update state only on valid transitions. Fire listeners after state change.",solutionExplanation:"State machines eliminate illegal states and transitions. All valid transitions are explicitly declared, preventing bugs from invalid state changes."},
  {lessonId:30,difficulty:"Medium",topic:"JavaScript Patterns",title:"Repository Pattern",problemStatement:"Implement a repository pattern that abstracts data access. Create a UserRepository with in-memory storage that can be swapped for a real DB.",examples:"userRepo.findById(1). userRepo.save(user). userRepo.findAll({role:'admin'})",starterCodeJs:"class InMemoryRepository {\n  constructor() { this.store = new Map(); this.nextId = 1; }\n  async findById(id) { return this.store.get(id) || null; }\n  async findAll(filter = {}) {\n    return [...this.store.values()].filter(item =>\n      Object.entries(filter).every(([k,v]) => item[k] === v)\n    );\n  }\n  async save(entity) {\n    if (!entity.id) entity = { ...entity, id: this.nextId++, createdAt: new Date() };\n    else entity = { ...entity, updatedAt: new Date() };\n    this.store.set(entity.id, entity);\n    return entity;\n  }\n  async delete(id) { return this.store.delete(id); }\n  async count(filter = {}) { return (await this.findAll(filter)).length; }\n}\nconst userRepo = new InMemoryRepository();\n// Swap with: const userRepo = new PrismaUserRepository(prisma);",hints:"Repository hides storage implementation. All async even for in-memory so interface matches real DB. Save handles create vs update.",solutionExplanation:"Repository pattern enables swapping storage without changing business logic. Tests use in-memory; production uses real DB."},
  {lessonId:30,difficulty:"Hard",topic:"JavaScript Patterns",title:"Middleware Pipeline",problemStatement:"Implement Express-style middleware pipeline: functions called in sequence with (ctx, next). Support async middleware and error handling middleware.",examples:"pipeline.use(logger).use(auth).use(handler). pipeline.run(ctx) executes in order.",starterCodeJs:"class Pipeline {\n  constructor() { this.middlewares = []; }\n  use(fn) { this.middlewares.push(fn); return this; }\n  async run(ctx) {\n    let index = -1;\n    const dispatch = async (i) => {\n      if (i <= index) throw new Error('next() called multiple times');\n      index = i;\n      const fn = this.middlewares[i];\n      if (!fn) return;\n      try {\n        await fn(ctx, () => dispatch(i + 1));\n      } catch(e) {\n        const errorHandler = this.middlewares.find((f,j) => j > i && f.length >= 3);\n        if (errorHandler) await errorHandler(e, ctx, () => dispatch(this.middlewares.indexOf(errorHandler)+1));\n        else throw e;\n      }\n    };\n    return dispatch(0);\n  }\n}",hints:"Dispatch function takes index. next() calls dispatch(i+1). Error handlers have 3 params (error, ctx, next).",solutionExplanation:"This is how Koa and Express work internally. Each middleware calls next() to pass control. Not calling next() stops the chain."},
  {lessonId:30,difficulty:"Easy",topic:"JavaScript Patterns",title:"Strategy Pattern",problemStatement:"Implement sorting strategies (bubble, merge, quick) behind a Sorter interface. Switch algorithms at runtime.",examples:"sorter.setStrategy(mergeSort). sorter.sort([3,1,2]) uses mergeSort.",starterCodeJs:"const strategies = {\n  bubble: arr => {\n    const a = [...arr];\n    for (let i=0; i<a.length; i++) for (let j=0; j<a.length-i-1; j++) if (a[j]>a[j+1]) [a[j],a[j+1]]=[a[j+1],a[j]];\n    return a;\n  },\n  native: arr => [...arr].sort((a,b) => a-b),\n  merge: arr => arr.length<=1 ? arr : (() => {\n    const m = Math.floor(arr.length/2);\n    const merge = (a,b) => { const r=[]; while(a.length&&b.length) r.push(a[0]<b[0]?a.shift():b.shift()); return [...r,...a,...b]; };\n    return merge(strategies.merge(arr.slice(0,m)), strategies.merge(arr.slice(m)));\n  })()\n};\nclass Sorter {\n  constructor(strategy = 'native') { this.strategy = strategies[strategy]; }\n  setStrategy(name) { this.strategy = strategies[name]; return this; }\n  sort(arr) { return this.strategy(arr); }\n}",hints:"Strategy object maps names to functions. Sorter delegates to the current strategy. Switching strategy doesn't change client code.",solutionExplanation:"Strategy pattern decouples algorithm from context. Client code calls sort() without knowing which algorithm runs."},
  {lessonId:30,difficulty:"Medium",topic:"JavaScript Patterns",title:"Proxy-based Validation",problemStatement:"Use Proxy to create a type-safe object schema where each property is validated on set. Support required fields check on read.",examples:"const user = schema({name:'string', age:'number'}). user.name=42 throws TypeError.",starterCodeJs:"function schema(definitions) {\n  const data = {};\n  const required = Object.keys(definitions).filter(k => !definitions[k].startsWith('?'));\n  return new Proxy(data, {\n    set(target, prop, value) {\n      const type = (definitions[prop] || '').replace('?','');\n      if (!type) throw new Error(`Unknown property: ${prop}`);\n      if (value !== null && value !== undefined && typeof value !== type) throw new TypeError(`${prop} must be ${type}, got ${typeof value}`);\n      target[prop] = value;\n      return true;\n    },\n    get(target, prop) {\n      if (prop === 'validate') {\n        return () => required.filter(k => target[k] == null).map(k => `${k} is required`);\n      }\n      return target[prop];\n    }\n  });\n}",hints:"Proxy set validates type. Prefix ? in type string makes field optional. validate() method checks required fields.",solutionExplanation:"Proxy-based validation runs at assignment time, not at call time. This catches type errors immediately rather than when values are used."},
  {lessonId:30,difficulty:"Hard",topic:"JavaScript Patterns",title:"Lazy Loading Proxy",problemStatement:"Create a lazy-loading proxy that instantiates an expensive object only when its properties are first accessed.",examples:"const db = lazyLoad(() => new DatabaseConnection()). db.query() creates connection on first access.",starterCodeJs:"function lazyLoad(factory) {\n  let instance = null;\n  let initializing = false;\n  return new Proxy({}, {\n    get(_, prop) {\n      if (!instance) {\n        if (initializing) throw new Error('Circular lazy init detected');\n        initializing = true;\n        instance = factory();\n        initializing = false;\n      }\n      const val = instance[prop];\n      return typeof val === 'function' ? val.bind(instance) : val;\n    },\n    set(_, prop, value) {\n      if (!instance) instance = factory();\n      instance[prop] = value;\n      return true;\n    }\n  });\n}\nconst db = lazyLoad(() => { console.log('DB connected'); return new Map(); });\n// Connection only happens on first access\ndb.set('key', 'value'); // 'DB connected' logged here",hints:"Store instance as null. Create on first property access. Bind methods to instance to preserve 'this'. Detect circular init.",solutionExplanation:"Lazy initialization defers expensive setup until needed. Useful for database connections, large objects, and optional dependencies."}
];

async function main() {
  let ci = 0, cs = 0;
  for (const q of codingQuestions) {
    const exists = await p.practiceQuestion.findFirst({ where: { lessonId: q.lessonId, title: q.title } });
    if (!exists) { await p.practiceQuestion.create({ data: q }); ci++; } else cs++;
  }
  console.log(`Coding: ${ci} inserted, ${cs} skipped.`);
}

main().catch(console.error).finally(() => p.$disconnect());
